// Ejecución ÚNICA: procesar la tarea y generar resultado
const item = $input.item.json;

// Aquí va tu lógica personalizada según la descripción.
// Puedes usar sub-workflows, APIs externas, scraping, etc.
const description = item.description || item.title || 'Tarea sin descripción';
const title = item.title || 'Automatización';

// Ejemplo: simplemente confirmar la ejecución.
// En producción, aquí conectarías con APIs externas, 
// enviarías correos, consultarías bases de datos, etc.
let result = `✅ Tarea completada: ${description}`;
let status = 'success';

try {
  // ── Tu lógica aquí ──
  // Ejemplo: si la descripción menciona "noticias", podrías
  // llamar a una API de noticias y formatear el resultado.

  if (description.toLowerCase().includes('noticias')) {
    result = `📰 Resumen de noticias del día:\n\n`
      + `• Tecnología: Las principales novedades del sector tech...\n`
      + `• Negocios: Mercados cierran en positivo...\n`
      + `• Deportes: Resultados de la jornada...\n\n`
      + `(Este es un ejemplo — conecta tu fuente de noticias real)`;
  } else if (description.toLowerCase().includes('clima') || description.toLowerCase().includes('weather')) {
    result = `🌤️ Reporte del clima:\n\nTemperatura: 22°C\nHumedad: 65%\nCondición: Parcialmente nublado\n\n(Conecta la API de clima real)`;
  } else if (description.toLowerCase().includes('correo') || description.toLowerCase().includes('email')) {
    result = `📧 Revisión de correos:\n\n• 3 correos nuevos\n• 1 urgente de Recursos Humanos\n• 2 newsletters\n\n(Conecta tu API de correos)`;
  } else {
    result = `✅ Ejecutado: ${description}\n\nLa automatización se ejecutó correctamente.`;
  }
} catch (error) {
  status = 'failed';
  result = `❌ Error al ejecutar: ${error.message}`;
}

return {
  json: {
    automationId: item.id,
    status,
    result,
    title,
    description,
    logs: {
      executedAt: new Date().toISOString(),
      type: 'once'
    }
  }
};

// Ejecución RECURRENTE: procesar la tarea periódica
const item = $input.item.json;

const description = item.description || item.title || 'Tarea sin descripción';
const title = item.title || 'Automatización';
const frequency = item.schedule?.frequency || 'daily';
const runCount = (item.runCount || 0) + 1;

let result = '';
let status = 'success';

try {
  // ── Tu lógica recurrente aquí ──
  // Cada frecuencia puede tener su propia lógica.

  if (description.toLowerCase().includes('noticias')) {
    result = `📰 Noticias del día (ejecución #${runCount}):\n\n`
      + `• IA: OpenAI lanza nuevo modelo...\n`
      + `• Tech: Apple presenta nuevos productos...\n`
      + `• Finanzas: Bitcoin supera los $100k...\n\n`
      + `Próxima entrega: ${frequency === 'daily' ? 'mañana' : 'próxima semana'}`;
  } else if (description.toLowerCase().includes('reporte') || description.toLowerCase().includes('informe')) {
    result = `📊 Reporte automático #${runCount}:\n\n`
      + `• Usuarios activos: 156\n`
      + `• Mensajes enviados: 1,234\n`
      + `• Tareas completadas: 42\n\n`
      + `(Conecta tu base de datos para datos reales)`;
  } else if (description.toLowerCase().includes('recordatorio') || description.toLowerCase().includes('recuerda')) {
    result = `🔔 Recordatorio #${runCount}:\n\n${description}\n\nNo olvides completar esta tarea.`;
  } else if (description.toLowerCase().includes('correo') || description.toLowerCase().includes('email')) {
    result = `📧 Revisión de correos #${runCount}:\n\n`
      + `• ${Math.floor(Math.random() * 10) + 1} correos nuevos\n`
      + `• ${Math.floor(Math.random() * 3)} urgentes\n\n`
      + `(Conecta tu API de correos para datos reales)`;
  } else {
    result = `⚡ Ejecución #${runCount} completada:\n${description}`;
  }
} catch (error) {
  status = 'failed';
  result = `❌ Error en ejecución #${runCount}: ${error.message}`;
}

return {
  json: {
    automationId: item.id,
    status,
    result,
    title,
    description,
    logs: {
      executedAt: new Date().toISOString(),
      type: frequency,
      runNumber: runCount
    }
  }
};

// Procesa mensajes que el usuario envía directamente al canal del agente.
// El webhook recibe el payload completo de Clowpen con historial.
const body = $input.item.json.body || $input.item.json;
const event = body.event; // 'message.created' o 'task.forwarded'
const data = body.data || {};

const content = data.content || '';
const senderName = data.senderName || 'Usuario';
const channelId = data.channelId || '';
const history = data.conversationHistory || [];

// Analizar el mensaje del usuario para decidir qué hacer
let responseMessage = '';
let actions = [];

const lowerContent = content.toLowerCase();

if (lowerContent.includes('estado') || lowerContent.includes('status')) {
  responseMessage = `📋 Estado actual del agente:\n\n`
    + `• Agente: Activo y funcionando\n`
    + `• Automatizaciones monitoreadas: Polling cada 5 min\n`
    + `• Última verificación: ${new Date().toLocaleString('es-CO')}\n\n`
    + `¿Necesitas algo más?`;
} else if (lowerContent.includes('ayuda') || lowerContent.includes('help')) {
  responseMessage = `🤖 Soy tu agente de automatizaciones. Puedo:\n\n`
    + `• ⏰ Programar tareas recurrentes\n`
    + `• 📰 Enviar noticias diarias\n`
    + `• 🔔 Crear recordatorios\n`
    + `• 📊 Generar reportes periódicos\n`
    + `• 📧 Revisar correos automáticamente\n\n`
    + `Escribe en cualquier canal algo como "envíame noticias todos los días a las 8am" y el observador me lo reenviará.`;
  actions = [
    { label: '📰 Noticias diarias', actionType: 'custom', payload: { response: 'Quiero recibir noticias diarias a las 8am' }, style: 'primary' },
    { label: '📊 Reporte semanal', actionType: 'custom', payload: { response: 'Genera un reporte semanal los lunes' }, style: 'secondary' }
  ];
} else if (event === 'task.forwarded') {
  const taskDesc = data.taskDescription || content;
  responseMessage = `✅ Recibí la tarea reenviada:\n\n"${taskDesc}"\n\nProcesando... Te notificaré cuando esté lista.`;
} else {
  responseMessage = `Recibido: "${content}"\n\nEstoy procesando tu solicitud. Si necesitas ayuda, escribe "ayuda".`;
}

return {
  json: {
    message: responseMessage,
    actions,
    channelId,
    senderName
  }
};
